mapper.select:
SELECT * FROM oa_approval_cc
WHERE record_id = #{recordId}
ORDER BY create_time ASC

SELECT ac.id, ac.cc_user_id AS ccUserId, ac.cc_user_name AS ccUserName,
       CASE WHEN ac.is_read = TRUE THEN 1 ELSE 0 END AS isRead,
       ac.read_time AS readTime, ac.create_time AS createTime,
       ar.record_no AS recordNo, ar.business_type AS businessType, ar.title
FROM oa_approval_cc ac
INNER JOIN oa_approval_record ar ON ac.record_id = ar.id
WHERE ac.cc_user_id = #{userId}
AND ac.is_read = #{isRead}
ORDER BY ac.create_time DESC
LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*)
FROM oa_approval_cc ac
WHERE ac.cc_user_id = #{userId}
AND ac.is_read = #{isRead}
